import{_ as e,o as t,c as o,a4 as r}from"./chunks/framework.4M7SpZrd.js";const u=JSON.parse('{"title":"Busca — Fluxos e Regras","description":"","frontmatter":{},"headers":[],"relativePath":"api/search.md","filePath":"api/search.md"}'),s={name:"api/search.md"};function d(i,a,l,n,c,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="busca-—-fluxos-e-regras" tabindex="-1">Busca — Fluxos e Regras <a class="header-anchor" href="#busca-—-fluxos-e-regras" aria-label="Permalink to &quot;Busca — Fluxos e Regras&quot;">​</a></h1><blockquote><p><strong>Endpoints completos:</strong> <a href="http://kubex.test/api/docs#/search" target="_blank" rel="noreferrer">Swagger UI — Search</a> | <a href="http://kubex.test/api/docs#/name-search" target="_blank" rel="noreferrer">Name Search</a></p></blockquote><h2 id="busca-por-imagem-search" tabindex="-1">Busca por Imagem (<code>/search</code>) <a class="header-anchor" href="#busca-por-imagem-search" aria-label="Permalink to &quot;Busca por Imagem (`/search`)&quot;">​</a></h2><ol><li>Upload <code>multipart/form-data</code> (JPEG/PNG/WebP/GIF, max 10MB)</li><li>PIL verify → pHash/dHash/aHash → thumbnail</li><li>Cria <code>ContentHash</code> + <code>SearchJob</code> (status <code>pending</code>)</li><li>Enfileira Celery task para Lens (SerpAPI Google Lens + Social Reverse + Google Images Direct)</li><li>Job IDs sao <code>public_id</code> hex (16 chars, nao sequenciais)</li></ol><h3 id="progresso-em-tempo-real" tabindex="-1">Progresso em Tempo Real <a class="header-anchor" href="#progresso-em-tempo-real" aria-label="Permalink to &quot;Progresso em Tempo Real&quot;">​</a></h3><p>O sistema oferece progresso granular durante a busca:</p><ul><li><strong>Celery worker</strong> escreve progresso no Redis (<code>job_progress:{public_id}</code>, TTL 5min)</li><li><strong>Endpoint</strong> <code>GET /v1/search/jobs/{job_id}/progress</code> retorna step atual, %, posicao na fila</li><li><strong>Frontend</strong> poll a cada 2 segundos com progress bar animada e indicadores de etapa</li></ul><p><strong>Etapas da busca por imagem:</strong></p><ol><li>Lendo imagem</li><li>Buscando nos motores de busca</li><li>Calculando similaridade real (pHash enrichment)</li><li>Salvando resultados</li><li>Finalizando analise</li></ol><p><strong>Etapas da busca por nome:</strong></p><ol><li>Preparando variacoes do nome</li><li>Buscando em fontes externas</li><li>Salvando resultados</li><li>Finalizando analise</li></ol><h3 id="phash-enrichment" tabindex="-1">pHash Enrichment <a class="header-anchor" href="#phash-enrichment" aria-label="Permalink to &quot;pHash Enrichment&quot;">​</a></h3><p>Apos receber resultados das APIs, os thumbnails sao baixados e comparados via pHash contra a imagem original. O score posicional e substituido pela similaridade real (0-100%). Resultados sao re-ordenados por similaridade.</p><h2 id="busca-por-nome-—-brandwatch-name-search" tabindex="-1">Busca por Nome — BrandWatch (<code>/name-search</code>) <a class="header-anchor" href="#busca-por-nome-—-brandwatch-name-search" aria-label="Permalink to &quot;Busca por Nome — BrandWatch (`/name-search`)&quot;">​</a></h2><ul><li>Gera variacoes do nome (<code>text_normalizer</code> + <code>name_variation</code>)</li><li>Busca nos <code>CrawlTargets</code> configurados</li><li>Requer plano <strong>Pro+</strong></li></ul><h2 id="search-vs-monitoring" tabindex="-1">Search vs Monitoring <a class="header-anchor" href="#search-vs-monitoring" aria-label="Permalink to &quot;Search vs Monitoring&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><code>POST /search/image</code></th><th><code>POST /monitoring/images</code></th></tr></thead><tbody><tr><td>Cria SearchJob</td><td>Sim</td><td>Nao</td></tr><tr><td>Dispara Celery task</td><td>Sim</td><td>Nao</td></tr><tr><td>Cria ContentHash</td><td>Sim</td><td>Sim</td></tr><tr><td>Resultado imediato</td><td>Sim (busca reversa)</td><td>Nao (entra no ciclo automatico)</td></tr><tr><td>Frontend</td><td><code>/dashboard/buscar-imagem</code></td><td><code>/dashboard/monitoramento</code></td></tr></tbody></table><h2 id="quotas" tabindex="-1">Quotas <a class="header-anchor" href="#quotas" aria-label="Permalink to &quot;Quotas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plano</th><th>Buscas/mes</th><th>Resultados visiveis</th><th>Nomes monitorados</th></tr></thead><tbody><tr><td>Gratuito</td><td>5</td><td>3</td><td>0</td></tr><tr><td>Essencial</td><td>50</td><td>999</td><td>5</td></tr><tr><td>Pro</td><td>Ilimitado</td><td>999</td><td>50</td></tr><tr><td>Fundador</td><td>100</td><td>999</td><td>20</td></tr><tr><td>Premium</td><td>Ilimitado</td><td>999</td><td>999</td></tr></tbody></table>',19)])])}const p=e(s,[["render",d]]);export{u as __pageData,p as default};
